from dataclasses import dataclass
from typing import Any, Optional

@dataclass
class Event:
    start: float
    end: float
    title: str
    priority: int  # higher = more important

class Calendar:
    def __init__(self):
        self._events: list[Event] = []

    def add_event(self, event: Event) -> list[Event]:
        if event.start >= event.end:
            raise ValueError("start must be less than end")

        added_fragments = []
        affected_old = []
        current_start = event.start
        current_end = event.end

        new_events = []
        i = 0
        n = len(self._events)

        while i < n:
            old = self._events[i]

            if old.end <= current_start or old.start >= current_end:
                new_events.append(old)
                i += 1
                continue

            overlap_start = max(current_start, old.start)
            overlap_end = min(current_end, old.end)

            if event.priority > old.priority:
                if old.start < overlap_start:
                    new_events.append(Event(old.start, overlap_start, old.title, old.priority))
                    affected_old.append(Event(old.start, overlap_start, old.title, old.priority))
                if old.end > overlap_end:
                    new_events.append(Event(overlap_end, old.end, old.title, old.priority))
                    affected_old.append(Event(overlap_end, old.end, old.title, old.priority))
                current_start = overlap_end
            else:
                if current_start < overlap_start:
                    added_fragments.append(Event(current_start, overlap_start, event.title, event.priority))
                current_start = overlap_end
            i += 1

        if current_start < current_end:
            added_fragments.append(Event(current_start, current_end, event.title, event.priority))

        # Merge and sort
        merged = new_events + added_fragments
        merged.sort(key=lambda e: e.start)
        self._events = merged

        return affected_old if affected_old else added_fragments

    def get_events(self, start: float, end: float) -> list[Event]:
        return [e for e in self._events if e.start < end and e.end > start]

    def free_slots(self, start: float, end: float, min_duration: float = 0) -> list[tuple[float, float]]:
        slots = []
        current = start
        for e in self._events:
            if e.start >= end:
                break
            if e.end <= start:
                continue
            gap_start = max(current, e.end)
            gap_end = min(end, e.start) if e.start < end else end
            if gap_start < gap_end and (gap_end - gap_start) >= min_duration:
                slots.append((gap_start, gap_end))
            current = max(current, e.end)
        if current < end and (end - current) >= min_duration:
            slots.append((current, end))
        return slots

    def utilization(self, start: float, end: float) -> float:
        total = end - start
        if total <= 0:
            return 0.0
        occupied = 0.0
        for e in self._events:
            if e.end <= start or e.start >= end:
                continue
            occupied += min(e.end, end) - max(e.start, start)
        return occupied / total
